1	// CLI: reads JSON scenario from stdin, writes {results:[...]} to stdout.
2	import { readFileSync } from "node:fs";
3	import { quote, claim } from "./claim-office.js";
4	
5	const scenario = JSON.parse(readFileSync(0, "utf-8"));
6	const yearsWithMHPCO = scenario.customer.yearsWithMHPCO;
7	
8	const results = [];
9	const quoteSteps = [];
10	let seenQuote = false;
11	
12	for (const step of scenario.steps) {
13	  if (step.op === "quote") {
14	    const { premium } = quote({
15	      items: step.items,
16	      yearsWithMHPCO,
17	      firstInsurance: true,
18	      followUp: seenQuote,
19	    });
20	    quoteSteps.push(step);
21	    seenQuote = true;
22	    results.push({ premium });
23	  } else if (step.op === "claim") {
24	    const items = quoteSteps[step.policy].items;
25	    const { payout, remainingCap } = claim(items, step.incident);
26	    results.push({ payout, remainingCap });
27	  }
28	}
29	
30	process.stdout.write(JSON.stringify({ results }));
31	process.exit(0);
32

1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteInput {
9	  items: Item[];
10	  yearsWithMHPCO?: number;
11	  firstInsurance?: boolean;
12	  followUp?: boolean;
13	}
14	
15	export interface QuoteResult {
16	  premium: number;
17	}
18	
19	const PROCESSING_FEE = 5;
20	const DEFAULT_BASE_PREMIUM = 100;
21	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
22	  amulet: 60,
23	  staff: 80,
24	  potion: 40,
25	  rune: 25,
26	  moonstone: 25,
27	};
28	
29	const CURSE_SURCHARGE_RATE = 0.5;
30	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
31	
32	function unmodifiedBasePremiumFor(item: Item): number {
33	  return BASE_PREMIUM_BY_TYPE[item.type] ?? DEFAULT_BASE_PREMIUM;
34	}
35	
36	function basePremiumFor(item: Item): number {
37	  const base = unmodifiedBasePremiumFor(item);
38	  const highEnchantmentSurcharge =
39	    item.enchantment !== undefined && item.enchantment >= 5
40	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE
41	      : 0;
42	  const curseSurcharge = item.cursed ? CURSE_SURCHARGE_RATE : 0;
43	  return base * (1 + highEnchantmentSurcharge + curseSurcharge);
44	}
45	
46	const BLOCK_SIZE = 3;
47	const BLOCK_PREMIUM = 60;
48	
49	const LOYALTY_DISCOUNT_RATE = 0.2;
50	const LOYALTY_MIN_YEARS = 2;
51	
52	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
53	
54	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
55	
56	function rateOfBaseWhen(
57	  condition: boolean | undefined,
58	  basePremium: number,
59	  rate: number,
60	): number {
61	  return condition ? basePremium * rate : 0;
62	}
63	
64	function groupByType(items: Item[]): Map<string, Item[]> {
65	  const groups = new Map<string, Item[]>();
66	  for (const item of items) {
67	    const group = groups.get(item.type) ?? [];
68	    group.push(item);
69	    groups.set(item.type, group);
70	  }
71	  return groups;
72	}
73	
74	function basePremiumForGroup(group: Item[]): number {
75	  if (group.length === BLOCK_SIZE) {
76	    return BLOCK_PREMIUM;
77	  }
78	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
79	}
80	
81	export interface Damage {
82	  itemType: string;
83	  amount: number;
84	}
85	
86	export interface Incident {
87	  cause: string;
88	  damages: Damage[];
89	}
90	
91	export interface ClaimResult {
92	  payout: number;
93	  remainingCap: number;
94	}
95	
96	const DEDUCTIBLE = 100;
97	const CAP_MULTIPLIER = 2;
98	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
99	  sword: 1000,
100	  amulet: 600,
101	  staff: 800,
102	  potion: 400,
103	  rune: 250,
104	  moonstone: 250,
105	};
106	
107	function insuranceValueFor(item: Item): number {
108	  return INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
109	}
110	
111	function capFor(items: Item[]): number {
112	  const insuranceSum = items.reduce(
113	    (sum, item) => sum + insuranceValueFor(item),
114	    0,
115	  );
116	  return CAP_MULTIPLIER * insuranceSum;
117	}
118	
119	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
120	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
121	
122	function reimbursableFor(item: Item | undefined, amount: number): number {
123	  if (
124	    item?.enchantment !== undefined &&
125	    item.enchantment >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD
126	  ) {
127	    return amount * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
128	  }
129	  return amount;
130	}
131	
132	function payoutForDamage(items: Item[], damage: Damage): number {
133	  const item = items.find((candidate) => candidate.type === damage.itemType);
134	  const reimbursable = reimbursableFor(item, damage.amount);
135	  return Math.max(0, reimbursable - DEDUCTIBLE);
136	}
137	
138	function rawPayoutFor(items: Item[], incident: Incident): number {
139	  return incident.damages.reduce(
140	    (sum, damage) => sum + payoutForDamage(items, damage),
141	    0,
142	  );
143	}
144	
145	export function claim(
146	  items: Item[],
147	  incident: Incident,
148	  currentCap: number = capFor(items),
149	): ClaimResult {
150	  const payout = Math.min(Math.floor(rawPayoutFor(items, incident)), currentCap);
151	  const remainingCap = currentCap - payout;
152	  return { payout, remainingCap };
153	}
154	
155	export function quote(input: QuoteInput): QuoteResult {
156	  const groups = [...groupByType(input.items).values()];
157	  const basePremium = groups.reduce(
158	    (sum, group) => sum + basePremiumForGroup(group),
159	    0,
160	  );
161	
162	  const unmodifiedBasePremium = input.items.reduce(
163	    (sum, item) => sum + unmodifiedBasePremiumFor(item),
164	    0,
165	  );
166	
167	  const firstInsuranceSurcharge = rateOfBaseWhen(
168	    input.firstInsurance,
169	    unmodifiedBasePremium,
170	    FIRST_INSURANCE_SURCHARGE_RATE,
171	  );
172	
173	  const followUpDiscount = rateOfBaseWhen(
174	    input.followUp,
175	    unmodifiedBasePremium,
176	    FOLLOW_UP_DISCOUNT_RATE,
177	  );
178	
179	  const qualifiesForLoyalty =
180	    input.yearsWithMHPCO !== undefined &&
181	    input.yearsWithMHPCO >= LOYALTY_MIN_YEARS;
182	  const loyaltyDiscount = rateOfBaseWhen(
183	    qualifiesForLoyalty,
184	    unmodifiedBasePremium,
185	    LOYALTY_DISCOUNT_RATE,
186	  );
187	
188	  const surcharges = firstInsuranceSurcharge;
189	  const discounts = loyaltyDiscount + followUpDiscount;
190	
191	  const rawPremium = basePremium + surcharges - discounts + PROCESSING_FEE;
192	
193	  return {
194	    premium: Math.ceil(rawPremium),
195	  };
196	}
