const results = [];
const quoteSteps = [];
let seenQuote = false;

for (const step of scenario.steps) {
  if (step.op === "quote") {
    const { premium } = quote({
      items: step.items,
      yearsWithMHPCO,
      firstInsurance: true,
      followUp: seenQuote,
    });
    quoteSteps.push(step);
    seenQuote = true;
    results.push({ premium });
  } else if (step.op === "claim") {
    const items = quoteSteps[step.policy].items;
